#include <iostream>
#include <vector>

using namespace std;

int dr[] = {1, -1, 0, 0};
int dc[] = {0, 0, 1, -1};

void dfs(int row, int col, vector<vector<bool>> &visited, int rows, int cols)
{
    visited[row][col] = true;
    cout << row << "," << col << " ";

    for (int i = 0; i < 4; i++)
    {
        int newRow = row + dr[i];
        int newCol = col + dc[i];

        if (newRow >= 0 && newRow < rows && newCol >= 0 && newCol < cols && !visited[newRow][newCol])
        {
            dfs(newRow, newCol, visited, rows, cols); // commit to this neighbor FULLY before trying the next
        }
    }
}

int main()
{
    int rows = 3, cols = 3;
    vector<vector<bool>> visited(rows, vector<bool>(cols, false));

    dfs(0, 0, visited, rows, cols);

    return 0;
}

